import React from 'react';
import { useParams, Link } from 'react-router-dom';
import Navbar from '../components/Navbar';
import './ProjetoDetalhes.css';

function ProjetoDetalhes() {
  const { id } = useParams();

  const projetoInfo = {
    id: id,
    nome: 'Projeto Integrador 1',
    descricao: 'Desenvolvimento do sistema colaborativo TaskFlow resolvendo problemas de organização.',
    tarefas: [
      { id: 1, titulo: 'Estruturação do Layout React', responsavel: 'Lucas', prazo: '24/05/2026', status: 'Em Andamento' },
      { id: 2, titulo: 'Configuração do React Router', responsavel: 'Sheila', prazo: '20/05/2026', status: 'Concluído' },
      { id: 3, titulo: 'Estilização Base com CSS', responsavel: 'Você', prazo: '28/05/2026', status: 'Pendente' }
    ]
  };

  return (
    <div>
      <Navbar />
      <div className="detalhes-container">
        <div className="detalhes-header">
          <div>
            <h1>{projetoInfo.nome}</h1>
            <p>{projetoInfo.descricao}</p>
          </div>
          <Link to="/nova-tarefa" className="btn-nova-tarefa">Nova Tarefa</Link>
        </div>

        <h2>Tarefas do Projeto</h2>
        <div className="tarefas-lista">
          {projetoInfo.tarefas.map((tarefa) => (
            <div key={tarefa.id} className="tarefa-item">
              <div className="tarefa-info">
                <h4>{tarefa.titulo}</h4>
                <p>Responsável: {tarefa.responsavel} | Prazo: {tarefa.prazo}</p>
              </div>
              <span className={`status-tag ${tarefa.status.toLowerCase().replace(' ', '-')}`}>
                {tarefa.status}
              </span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

export default ProjetoDetalhes;
